    private final String name;
    private final String url;
    private final String hash;
    private static final StyledLogger LOGGER = new StyledLogger(Image.class);
    private static final Map<Image, SoftReference<BufferedImage>> CACHE = new EnumMap<>(Image.class);

    public BufferedImage get() {
        BufferedImage cached = getCached();
        if (cached != null) {
            return cached;
        }

        BufferedImage bufferedImage;
        try {
            bufferedImage = Images.loadImage(url, "idlescape");
        } catch (OutOfMemoryError error) {
            LOGGER.error(String.format("Failed to load image because the heap is exhausted: %s", name), error);
            throw new IllegalStateException("Failed to load image: " + name, error);
        }

        if (bufferedImage == null) {
            LOGGER.log(String.format("Failed to load image: %s", name));
            throw new IllegalStateException("Failed to load image: " + name);
        }
        cache(bufferedImage);
        return bufferedImage;
    }

    private BufferedImage getCached() {
        synchronized (CACHE) {
            SoftReference<BufferedImage> ref = CACHE.get(this);
            return ref == null ? null : ref.get();
        }
    }

    private void cache(BufferedImage image) {
        synchronized (CACHE) {
            CACHE.put(this, new SoftReference<>(image));
        }
    }
